<span class="line"><span class="token keyword">for</span> name <span class="token keyword">in</span> glob<span class="token punctuation">.</span>glob<span class="token punctuation">(</span><span class="token string">&#39;*[0-9]*.txt&#39;</span><span class="token punctuation">)</span><span class="token punctuation">:</span></span>
